#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
char buf[1<<23],*p1=buf,*p2=buf,obuf[1<<23],*O=obuf;
#define getchar() (p1==p2&&(p2=(p1=buf)+fread(buf,1,1<<21,stdin),p1==p2)?EOF:*p1++)
#define putchar(ch) (*O++=(ch))
#define Output() fwrite(obuf,O-obuf,1,stdout);
inline void rd(int &res)
{
	res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
}
inline void print(const int &x){if(x>9)print(x/10);putchar(x%10+'0');}
inline void pt(const int &x,const char &ch=-1){x<0?putchar('-'),print(-x):print(x);if(~ch)putchar(ch);}
const int N=1e6+10;int sml[N],num[N],pvl[N],pm[N>>2],cpt,prd[N];bool vs[N];
inline void Init(const int &mx=1e6)
{
	vs[1]=1;rep(2,mx,i)
	{
		if(!vs[i])num[pvl[sml[pm[++cpt]=i]=i]=i]=1;
		for(int j=1;j<=cpt&&pm[j]*i<=mx;++j)
		{
			int tmp=pm[j]*i;vs[tmp]=true;sml[tmp]=pm[j];
			if(sml[i]==pm[j])num[tmp]=num[i]+1,pvl[tmp]=pvl[i]*pm[j];
			else pvl[tmp]=pm[j],num[tmp]=1;if(!(i%pm[j]))break;
		}
	}
}
const int NN=2e5+10,Mod=1e9+7;int a[NN],t[NN],n,lst[N],ans[NN];
inline int qpow(int a,int b=Mod-2){int res(1);while(b)b&1?res=1ll*res*a%Mod:0,a=1ll*a*a%Mod,b=b>>1;return res;}
struct Sort{int l,r,idx;inline bool operator<(const Sort &x)const{return r<x.r;}}Q[NN];
inline int qry(int p){int r(1);while(p)r=1ll*r*t[p]%Mod,p^=(p&-p);return r;}
inline void add(int p,const int &v){while(p<=n)t[p]=1ll*t[p]*v%Mod,p+=(p&-p);}
inline void ins(const int &i)
{
	int x=a[i];while(x!=1)
	{
		int p=sml[x];add(i,p-1);add(i,qpow(p));
		if(lst[p])add(lst[p],qpow(p-1)),add(lst[p],p);lst[p]=i;x/=pvl[x];
	}
}
int main()
{
	int q,mx=0;rd(n);prd[0]=1;rep(1,n,i)rd(a[i]),prd[i]=1ll*prd[i-1]*a[i]%Mod,a[i]>mx?mx=a[i]:0;Init(mx);
	rd(q);rep(1,q,i)rd(Q[i].l),rd(Q[i].r),Q[i].idx=i;std::sort(Q+1,Q+q+1);rep(1,n,i)t[i]=1;
	int R=0;rep(1,q,i){while(R<Q[i].r)ins(++R);ans[Q[i].idx]=1ll*prd[Q[i].r]*qpow(prd[Q[i].l-1])%Mod*qry(Q[i].r)%Mod*qpow(qry(Q[i].l-1))%Mod;}
	rep(1,q,i)pt(ans[i],'\n');Output();return 0;
}
